BEGIN;
DO $$
DECLARE
  v_subject_id UUID;
  v_topic_id UUID;
  v_test_id BIGINT;
BEGIN
  SELECT id INTO v_subject_id FROM test_subjects WHERE name ILIKE '%cardio%' ORDER BY id LIMIT 1;
  IF v_subject_id IS NULL THEN
    INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular System', 'Cardiovascular notes') RETURNING id INTO v_subject_id;
  END IF;
  SELECT id INTO v_topic_id FROM test_topics WHERE name = 'Cardiomyopathy' ORDER BY (SELECT COUNT(*) FROM test_questions q WHERE q.topic_id = test_topics.id) DESC, created_at ASC LIMIT 1;
  IF v_topic_id IS NULL THEN
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (v_subject_id, 'Cardiomyopathy', 'Dilated, hypertrophic, restrictive, ARVC and nursing priorities', 'published') RETURNING id INTO v_topic_id;
  END IF;
  SELECT id INTO v_test_id FROM tests WHERE is_active = true ORDER BY id LIMIT 1;
  IF v_test_id IS NULL THEN
    INSERT INTO tests (test_name, system_category, description, is_active)
    VALUES ('Cardiovascular System - Cardiomyopathy (Generated)', 'Cardiovascular System', 'Auto-generated NCLEX question set', true)
    RETURNING id INTO v_test_id;
  END IF;
  DELETE FROM test_questions WHERE topic_id = v_topic_id AND category = 'Cardiomyopathy - NCLEX';
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Core definition in this cardiomyopathy scenario?', 'Which finding best supports Core definition in this cardiomyopathy scenario?', '[{"id": "a", "text": "Cardiomyopathy is heart muscle disease that can make the heart weak, stretched, or stiff and impair pumping."}, {"id": "b", "text": "Cardiomyopathy only affects coronary arteries in this note."}, {"id": "c", "text": "Cardiomyopathy never affects cardiac output in this note."}, {"id": "d", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}]'::jsonb, '["a"]'::jsonb, 'Correct because Cardiomyopathy is heart muscle disease that can make the heart weak, stretched, or stiff and impair pumping. Monitor for progression to heart failure, dysrhythmias, and sudden cardiac death.', 'Cardiomyopathy - NCLEX', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for subtype differentiation. Which interpretation matches Dilated cardiomyopathy pattern?', 'The nurse reviews data for subtype differentiation. Which interpretation matches Dilated cardiomyopathy pattern?', '[{"id": "a", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "b", "text": "Prioritize systolic failure monitoring and congestion assessment."}, {"id": "c", "text": "Dilated type has thick septum with normal chamber size in this note."}, {"id": "d", "text": "This pattern is more consistent with HCM symptoms."}]'::jsonb, '["b"]'::jsonb, 'Correct because Dilated cardiomyopathy has enlarged chambers, especially LV, with thin weak muscle and reduced ejection fraction. Prioritize systolic failure monitoring and congestion assessment.', 'Cardiomyopathy - NCLEX', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement is most accurate regarding Dilated causes?', 'Which statement is most accurate regarding Dilated causes?', '[{"id": "a", "text": "Dilated type is only caused by congenital cyanotic defects in this note."}, {"id": "b", "text": "This pattern is more consistent with HCM exacerbators."}, {"id": "c", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "d", "text": "Dilated causes listed include genetics, alcohol/drug use, viral myocarditis, peripartum state, and hypertension."}]'::jsonb, '["d"]'::jsonb, 'Correct because Dilated causes listed include genetics, alcohol/drug use, viral myocarditis, peripartum state, and hypertension. Address reversible contributors while managing HF symptoms.', 'Cardiomyopathy - NCLEX', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In high-priority cardiology triage, which conclusion fits Dilated signs?', 'In high-priority cardiology triage, which conclusion fits Dilated signs?', '[{"id": "a", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "b", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "c", "text": "Track fluid status and low-output symptoms to detect decompensation."}, {"id": "d", "text": "This pattern is more consistent with Restrictive pattern."}]'::jsonb, '["c"]'::jsonb, 'Correct because Dilated signs include SOB, fatigue, edema, S3 gallop, and displaced PMI. Track fluid status and low-output symptoms to detect decompensation.', 'Cardiomyopathy - NCLEX', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment aligns with HCM structure?', 'Which clinical judgment aligns with HCM structure?', '[{"id": "a", "text": "HCM is primarily chamber dilation in this note."}, {"id": "b", "text": "Hypertrophic cardiomyopathy features thickened myocardium, especially septum, causing outflow obstruction and decreased cardiac output."}, {"id": "c", "text": "HCM always improves outflow in this note."}, {"id": "d", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}]'::jsonb, '["b"]'::jsonb, 'Correct because Hypertrophic cardiomyopathy features thickened myocardium, especially septum, causing outflow obstruction and decreased cardiac output. Avoid interventions that worsen obstruction by reducing preload.', 'Cardiomyopathy - NCLEX', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports HCM risk profile in this cardiomyopathy scenario?', 'Which finding best supports HCM risk profile in this cardiomyopathy scenario?', '[{"id": "a", "text": "Enforce activity restrictions and high-risk counseling for athletes."}, {"id": "b", "text": "Athletic exertion is encouraged in HCM in this note."}, {"id": "c", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "d", "text": "HCM is non-genetic in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because HCM is genetic autosomal dominant and is the most common cause of sudden death in young athletes. Enforce activity restrictions and high-risk counseling for athletes.', 'Cardiomyopathy - NCLEX', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for subtype differentiation. Which interpretation matches HCM symptoms?', 'The nurse reviews data for subtype differentiation. Which interpretation matches HCM symptoms?', '[{"id": "a", "text": "This pattern is more consistent with ARVC epidemiology."}, {"id": "b", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "c", "text": "S3 is the hallmark HCM sound in this note."}, {"id": "d", "text": "HCM signs include exertional SOB, syncope, chest pain, and S4 gallop."}]'::jsonb, '["d"]'::jsonb, 'Correct because HCM signs include exertional SOB, syncope, chest pain, and S4 gallop. Treat exertional syncope/chest pain as red flags for obstructive physiology.', 'Cardiomyopathy - NCLEX', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement is most accurate regarding HCM exacerbators?', 'Which statement is most accurate regarding HCM exacerbators?', '[{"id": "a", "text": "Dehydration improves HCM symptoms in this note."}, {"id": "b", "text": "Nitrates are first-line for HCM obstruction in this note."}, {"id": "c", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "d", "text": "Maintain preload and avoid triggers that intensify obstruction."}]'::jsonb, '["d"]'::jsonb, 'Correct because HCM symptoms worsen with dehydration and Valsalva; nitrates should be avoided. Maintain preload and avoid triggers that intensify obstruction.', 'Cardiomyopathy - NCLEX', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In high-priority cardiology triage, which conclusion fits Restrictive pattern?', 'In high-priority cardiology triage, which conclusion fits Restrictive pattern?', '[{"id": "a", "text": "Restrictive type is primarily hypercontractile with easy filling in this note."}, {"id": "b", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "c", "text": "Restrictive cardiomyopathy has stiff myocardium with impaired filling and backup into lungs/body."}, {"id": "d", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}]'::jsonb, '["c"]'::jsonb, 'Correct because Restrictive cardiomyopathy has stiff myocardium with impaired filling and backup into lungs/body. Recognize diastolic failure signs despite less dramatic chamber enlargement.', 'Cardiomyopathy - NCLEX', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment aligns with Restrictive causes?', 'Which clinical judgment aligns with Restrictive causes?', '[{"id": "a", "text": "Radiation is unrelated to restrictive disease in this note."}, {"id": "b", "text": "Alcohol alone is the only restrictive cause in this note."}, {"id": "c", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "d", "text": "Search infiltrative or post-radiation etiologies in stiff-heart presentations."}]'::jsonb, '["d"]'::jsonb, 'Correct because Restrictive causes listed are amyloidosis, sarcoidosis, and radiation therapy. Search infiltrative or post-radiation etiologies in stiff-heart presentations.', 'Cardiomyopathy - NCLEX', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports ARVC pathology in this cardiomyopathy scenario?', 'Which finding best supports ARVC pathology in this cardiomyopathy scenario?', '[{"id": "a", "text": "ARVC has no arrhythmia risk in this note."}, {"id": "b", "text": "ARVC replaces right ventricular muscle with fat/scar tissue, creating dangerous arrhythmias and sudden death risk."}, {"id": "c", "text": "This pattern is more consistent with Assessment table: heart sounds."}, {"id": "d", "text": "ARVC primarily causes left ventricular dilation only in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because ARVC replaces right ventricular muscle with fat/scar tissue, creating dangerous arrhythmias and sudden death risk. Prioritize arrhythmia prevention and sudden-death mitigation in ARVC.', 'Cardiomyopathy - NCLEX', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for subtype differentiation. Which interpretation matches ARVC epidemiology?', 'The nurse reviews data for subtype differentiation. Which interpretation matches ARVC epidemiology?', '[{"id": "a", "text": "This pattern is more consistent with Assessment table: risks."}, {"id": "b", "text": "ARVC is exclusively acquired after age 80 in this note."}, {"id": "c", "text": "Screen family/sports history when unexplained syncope or palpitations occur."}, {"id": "d", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}]'::jsonb, '["c"]'::jsonb, 'Correct because ARVC is genetic autosomal dominant and often seen in young males and athletes. Screen family/sports history when unexplained syncope or palpitations occur.', 'Cardiomyopathy - NCLEX', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement is most accurate regarding ARVC diagnosis treatment?', 'Which statement is most accurate regarding ARVC diagnosis treatment?', '[{"id": "a", "text": "Echocardiogram alone is gold standard for ARVC in this note."}, {"id": "b", "text": "MRI is gold standard for ARVC; treatment includes ICD, amiodarone, activity restriction, and avoiding competitive sports."}, {"id": "c", "text": "ARVC treatment encourages strenuous sports in this note."}, {"id": "d", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}]'::jsonb, '["b"]'::jsonb, 'Correct because MRI is gold standard for ARVC; treatment includes ICD, amiodarone, activity restriction, and avoiding competitive sports. Use definitive imaging and aggressive prevention of lethal arrhythmias.', 'Cardiomyopathy - NCLEX', false, 13, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In high-priority cardiology triage, which conclusion fits Common pathophysiology?', 'In high-priority cardiology triage, which conclusion fits Common pathophysiology?', '[{"id": "a", "text": "Cardiomyopathy never leads to fluid overload in this note."}, {"id": "b", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "c", "text": "All types increase cardiac output in this note."}, {"id": "d", "text": "Trend perfusion and volume status regardless of subtype."}]'::jsonb, '["d"]'::jsonb, 'Correct because Across cardiomyopathies, reduced pumping lowers cardiac output and causes fatigue, dyspnea, and fluid buildup. Trend perfusion and volume status regardless of subtype.', 'Cardiomyopathy - NCLEX', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment aligns with Assessment table: EF?', 'Which clinical judgment aligns with Assessment table: EF?', '[{"id": "a", "text": "Dilated EF is normal in this note."}, {"id": "b", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "c", "text": "EF trends: dilated decreased, hypertrophic normal/increased, restrictive normal or decreased."}, {"id": "d", "text": "HCM always has reduced EF in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because EF trends: dilated decreased, hypertrophic normal/increased, restrictive normal or decreased. Interpret EF in subtype context instead of as isolated number.', 'Cardiomyopathy - NCLEX', false, 15, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Assessment table: heart sounds in this cardiomyopathy scenario?', 'Which finding best supports Assessment table: heart sounds in this cardiomyopathy scenario?', '[{"id": "a", "text": "No gallop sounds are associated with cardiomyopathy in this note."}, {"id": "b", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "c", "text": "Use auscultation pattern to support subtype differentiation."}, {"id": "d", "text": "This pattern is more consistent with Nursing fluid monitoring."}]'::jsonb, '["c"]'::jsonb, 'Correct because Heart sounds: dilated S3, hypertrophic S4, restrictive may have S3 or S4. Use auscultation pattern to support subtype differentiation.', 'Cardiomyopathy - NCLEX', false, 16, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for subtype differentiation. Which interpretation matches Assessment table: risks?', 'The nurse reviews data for subtype differentiation. Which interpretation matches Assessment table: risks?', '[{"id": "a", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "b", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "c", "text": "Risk patterns: dilated HF/thromboembolism, hypertrophic sudden death, restrictive HF."}, {"id": "d", "text": "Hypertrophic type has no sudden death risk in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Risk patterns: dilated HF/thromboembolism, hypertrophic sudden death, restrictive HF. Tailor surveillance to subtype-specific major complications.', 'Cardiomyopathy - NCLEX', false, 17, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement is most accurate regarding Medication strategy?', 'Which statement is most accurate regarding Medication strategy?', '[{"id": "a", "text": "Combine workload reduction, decongestion, and rhythm/thromboembolism prevention."}, {"id": "b", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "c", "text": "Antiarrhythmics are never used in this note."}, {"id": "d", "text": "This pattern is more consistent with HCM nursing teaching."}]'::jsonb, '["a"]'::jsonb, 'Correct because Medication classes listed include ACEi/ARB, beta-blockers, diuretics, anticoagulants (especially with A-fib), and antiarrhythmics like amiodarone. Combine workload reduction, decongestion, and rhythm/thromboembolism prevention.', 'Cardiomyopathy - NCLEX', false, 18, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In high-priority cardiology triage, which conclusion fits Device and advanced therapy?', 'In high-priority cardiology triage, which conclusion fits Device and advanced therapy?', '[{"id": "a", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "b", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "c", "text": "This pattern is more consistent with Peripartum alert."}, {"id": "d", "text": "Interventions include ICD, CRT, LVAD bridge to transplant, and heart transplant for end-stage dilated cardiomyopathy."}]'::jsonb, '["d"]'::jsonb, 'Correct because Interventions include ICD, CRT, LVAD bridge to transplant, and heart transplant for end-stage dilated cardiomyopathy. Escalate to device/mechanical support when medical therapy is insufficient.', 'Cardiomyopathy - NCLEX', false, 19, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment aligns with Lifestyle counseling?', 'Which clinical judgment aligns with Lifestyle counseling?', '[{"id": "a", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "b", "text": "This pattern is more consistent with Core definition."}, {"id": "c", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "d", "text": "Reinforce modifiable behaviors that reduce decompensation risk."}]'::jsonb, '["d"]'::jsonb, 'Correct because Patients are instructed to avoid alcohol, stimulants, and high-sodium diet. Reinforce modifiable behaviors that reduce decompensation risk.', 'Cardiomyopathy - NCLEX', false, 20, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Nursing fluid monitoring in this cardiomyopathy scenario?', 'Which finding best supports Nursing fluid monitoring in this cardiomyopathy scenario?', '[{"id": "a", "text": "A 5-lb weekly gain is always normal in this note."}, {"id": "b", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "c", "text": "Nursing priority: daily weights, and weight gain >2 lb/day indicates fluid retention requiring provider notification."}, {"id": "d", "text": "Daily weights are unnecessary in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Nursing priority: daily weights, and weight gain >2 lb/day indicates fluid retention requiring provider notification. Use rapid weight changes as early warning for worsening HF.', 'Cardiomyopathy - NCLEX', false, 21, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for subtype differentiation. Which interpretation matches Nursing respiratory/hemodynamic monitoring?', 'The nurse reviews data for subtype differentiation. Which interpretation matches Nursing respiratory/hemodynamic monitoring?', '[{"id": "a", "text": "This pattern is more consistent with Dilated causes."}, {"id": "b", "text": "Positioning and trend monitoring help detect and reduce decompensation."}, {"id": "c", "text": "SpO2 monitoring is not needed in this note."}, {"id": "d", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}]'::jsonb, '["b"]'::jsonb, 'Correct because Nursing monitoring includes I&O, vital signs, SpO2, and HOB elevation 30–45° for dyspnea relief. Positioning and trend monitoring help detect and reduce decompensation.', 'Cardiomyopathy - NCLEX', false, 22, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement is most accurate regarding HCM nursing teaching?', 'Which statement is most accurate regarding HCM nursing teaching?', '[{"id": "a", "text": "For HCM, teach no strenuous activity and avoidance of dehydration, Valsalva, and nitrates."}, {"id": "b", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "c", "text": "This pattern is more consistent with Dilated signs."}, {"id": "d", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}]'::jsonb, '["a"]'::jsonb, 'Correct because For HCM, teach no strenuous activity and avoidance of dehydration, Valsalva, and nitrates. Prevent obstruction-provoked collapse through targeted teaching.', 'Cardiomyopathy - NCLEX', false, 23, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In high-priority cardiology triage, which conclusion fits Peripartum alert?', 'In high-priority cardiology triage, which conclusion fits Peripartum alert?', '[{"id": "a", "text": "Screen new mothers promptly for cardiomyopathy warning symptoms."}, {"id": "b", "text": "Postpartum dyspnea is always benign in this note."}, {"id": "c", "text": "Peripartum cardiomyopathy only occurs years after delivery in this note."}, {"id": "d", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}]'::jsonb, '["a"]'::jsonb, 'Correct because Peripartum cardiomyopathy can occur in the last month of pregnancy or within 5 months postpartum, presenting with unexplained dyspnea/fatigue. Screen new mothers promptly for cardiomyopathy warning symptoms.', 'Cardiomyopathy - NCLEX', false, 24, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment aligns with Core definition?', 'Which clinical judgment aligns with Core definition?', '[{"id": "a", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "b", "text": "This pattern is more consistent with HCM risk profile."}, {"id": "c", "text": "Cardiomyopathy is heart muscle disease that can make the heart weak, stretched, or stiff and impair pumping."}, {"id": "d", "text": "Cardiomyopathy only affects coronary arteries in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Cardiomyopathy is heart muscle disease that can make the heart weak, stretched, or stiff and impair pumping. Monitor for progression to heart failure, dysrhythmias, and sudden cardiac death.', 'Cardiomyopathy - NCLEX', false, 25, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Dilated cardiomyopathy pattern in this cardiomyopathy scenario?', 'Which finding best supports Dilated cardiomyopathy pattern in this cardiomyopathy scenario?', '[{"id": "a", "text": "This pattern is more consistent with HCM symptoms."}, {"id": "b", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "c", "text": "Prioritize systolic failure monitoring and congestion assessment."}, {"id": "d", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}]'::jsonb, '["c"]'::jsonb, 'Correct because Dilated cardiomyopathy has enlarged chambers, especially LV, with thin weak muscle and reduced ejection fraction. Prioritize systolic failure monitoring and congestion assessment.', 'Cardiomyopathy - NCLEX', false, 26, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for subtype differentiation. Which interpretation matches Dilated causes?', 'The nurse reviews data for subtype differentiation. Which interpretation matches Dilated causes?', '[{"id": "a", "text": "Dilated causes listed include genetics, alcohol/drug use, viral myocarditis, peripartum state, and hypertension."}, {"id": "b", "text": "Hypertension is excluded in this note."}, {"id": "c", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "d", "text": "This pattern is more consistent with HCM exacerbators."}]'::jsonb, '["a"]'::jsonb, 'Correct because Dilated causes listed include genetics, alcohol/drug use, viral myocarditis, peripartum state, and hypertension. Address reversible contributors while managing HF symptoms.', 'Cardiomyopathy - NCLEX', false, 27, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement is most accurate regarding Dilated signs?', 'Which statement is most accurate regarding Dilated signs?', '[{"id": "a", "text": "S4 gallop is the defining dilated sound in this note."}, {"id": "b", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "c", "text": "This pattern is more consistent with Restrictive pattern."}, {"id": "d", "text": "Track fluid status and low-output symptoms to detect decompensation."}]'::jsonb, '["d"]'::jsonb, 'Correct because Dilated signs include SOB, fatigue, edema, S3 gallop, and displaced PMI. Track fluid status and low-output symptoms to detect decompensation.', 'Cardiomyopathy - NCLEX', false, 28, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In high-priority cardiology triage, which conclusion fits HCM structure?', 'In high-priority cardiology triage, which conclusion fits HCM structure?', '[{"id": "a", "text": "This pattern is more consistent with Restrictive causes."}, {"id": "b", "text": "HCM is primarily chamber dilation in this note."}, {"id": "c", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "d", "text": "Hypertrophic cardiomyopathy features thickened myocardium, especially septum, causing outflow obstruction and decreased cardiac output."}]'::jsonb, '["d"]'::jsonb, 'Correct because Hypertrophic cardiomyopathy features thickened myocardium, especially septum, causing outflow obstruction and decreased cardiac output. Avoid interventions that worsen obstruction by reducing preload.', 'Cardiomyopathy - NCLEX', false, 29, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment aligns with HCM risk profile?', 'Which clinical judgment aligns with HCM risk profile?', '[{"id": "a", "text": "Athletic exertion is encouraged in HCM in this note."}, {"id": "b", "text": "This pattern is more consistent with ARVC pathology."}, {"id": "c", "text": "Enforce activity restrictions and high-risk counseling for athletes."}, {"id": "d", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}]'::jsonb, '["c"]'::jsonb, 'Correct because HCM is genetic autosomal dominant and is the most common cause of sudden death in young athletes. Enforce activity restrictions and high-risk counseling for athletes.', 'Cardiomyopathy - NCLEX', false, 30, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports HCM symptoms in this cardiomyopathy scenario?', 'Which finding best supports HCM symptoms in this cardiomyopathy scenario?', '[{"id": "a", "text": "S3 is the hallmark HCM sound in this note."}, {"id": "b", "text": "HCM is always asymptomatic in this note."}, {"id": "c", "text": "This pattern is more consistent with ARVC epidemiology."}, {"id": "d", "text": "HCM signs include exertional SOB, syncope, chest pain, and S4 gallop."}]'::jsonb, '["d"]'::jsonb, 'Correct because HCM signs include exertional SOB, syncope, chest pain, and S4 gallop. Treat exertional syncope/chest pain as red flags for obstructive physiology.', 'Cardiomyopathy - NCLEX', false, 31, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for subtype differentiation. Which interpretation matches HCM exacerbators?', 'The nurse reviews data for subtype differentiation. Which interpretation matches HCM exacerbators?', '[{"id": "a", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "b", "text": "Maintain preload and avoid triggers that intensify obstruction."}, {"id": "c", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "d", "text": "This pattern is more consistent with ARVC diagnosis treatment."}]'::jsonb, '["b"]'::jsonb, 'Correct because HCM symptoms worsen with dehydration and Valsalva; nitrates should be avoided. Maintain preload and avoid triggers that intensify obstruction.', 'Cardiomyopathy - NCLEX', false, 32, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement is most accurate regarding Restrictive pattern?', 'Which statement is most accurate regarding Restrictive pattern?', '[{"id": "a", "text": "Restrictive cardiomyopathy has stiff myocardium with impaired filling and backup into lungs/body."}, {"id": "b", "text": "Restrictive type is primarily hypercontractile with easy filling in this note."}, {"id": "c", "text": "Restrictive type has no congestion risk in this note."}, {"id": "d", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}]'::jsonb, '["a"]'::jsonb, 'Correct because Restrictive cardiomyopathy has stiff myocardium with impaired filling and backup into lungs/body. Recognize diastolic failure signs despite less dramatic chamber enlargement.', 'Cardiomyopathy - NCLEX', false, 33, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In high-priority cardiology triage, which conclusion fits Restrictive causes?', 'In high-priority cardiology triage, which conclusion fits Restrictive causes?', '[{"id": "a", "text": "Radiation is unrelated to restrictive disease in this note."}, {"id": "b", "text": "Search infiltrative or post-radiation etiologies in stiff-heart presentations."}, {"id": "c", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "d", "text": "Alcohol alone is the only restrictive cause in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Restrictive causes listed are amyloidosis, sarcoidosis, and radiation therapy. Search infiltrative or post-radiation etiologies in stiff-heart presentations.', 'Cardiomyopathy - NCLEX', false, 34, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment aligns with ARVC pathology?', 'Which clinical judgment aligns with ARVC pathology?', '[{"id": "a", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "b", "text": "ARVC replaces right ventricular muscle with fat/scar tissue, creating dangerous arrhythmias and sudden death risk."}, {"id": "c", "text": "ARVC has no arrhythmia risk in this note."}, {"id": "d", "text": "This pattern is more consistent with Assessment table: heart sounds."}]'::jsonb, '["b"]'::jsonb, 'Correct because ARVC replaces right ventricular muscle with fat/scar tissue, creating dangerous arrhythmias and sudden death risk. Prioritize arrhythmia prevention and sudden-death mitigation in ARVC.', 'Cardiomyopathy - NCLEX', false, 35, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports ARVC epidemiology in this cardiomyopathy scenario?', 'Which finding best supports ARVC epidemiology in this cardiomyopathy scenario?', '[{"id": "a", "text": "Screen family/sports history when unexplained syncope or palpitations occur."}, {"id": "b", "text": "ARVC is exclusively acquired after age 80 in this note."}, {"id": "c", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "d", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}]'::jsonb, '["a"]'::jsonb, 'Correct because ARVC is genetic autosomal dominant and often seen in young males and athletes. Screen family/sports history when unexplained syncope or palpitations occur.', 'Cardiomyopathy - NCLEX', false, 36, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for subtype differentiation. Which interpretation matches ARVC diagnosis treatment?', 'The nurse reviews data for subtype differentiation. Which interpretation matches ARVC diagnosis treatment?', '[{"id": "a", "text": "MRI is gold standard for ARVC; treatment includes ICD, amiodarone, activity restriction, and avoiding competitive sports."}, {"id": "b", "text": "This pattern is more consistent with Medication strategy."}, {"id": "c", "text": "ARVC treatment encourages strenuous sports in this note."}, {"id": "d", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}]'::jsonb, '["a"]'::jsonb, 'Correct because MRI is gold standard for ARVC; treatment includes ICD, amiodarone, activity restriction, and avoiding competitive sports. Use definitive imaging and aggressive prevention of lethal arrhythmias.', 'Cardiomyopathy - NCLEX', false, 37, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement is most accurate regarding Common pathophysiology?', 'Which statement is most accurate regarding Common pathophysiology?', '[{"id": "a", "text": "Cardiomyopathy never leads to fluid overload in this note."}, {"id": "b", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "c", "text": "Trend perfusion and volume status regardless of subtype."}, {"id": "d", "text": "This pattern is more consistent with Device and advanced therapy."}]'::jsonb, '["c"]'::jsonb, 'Correct because Across cardiomyopathies, reduced pumping lowers cardiac output and causes fatigue, dyspnea, and fluid buildup. Trend perfusion and volume status regardless of subtype.', 'Cardiomyopathy - NCLEX', false, 38, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In high-priority cardiology triage, which conclusion fits Assessment table: EF?', 'In high-priority cardiology triage, which conclusion fits Assessment table: EF?', '[{"id": "a", "text": "HCM always has reduced EF in this note."}, {"id": "b", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "c", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "d", "text": "EF trends: dilated decreased, hypertrophic normal/increased, restrictive normal or decreased."}]'::jsonb, '["d"]'::jsonb, 'Correct because EF trends: dilated decreased, hypertrophic normal/increased, restrictive normal or decreased. Interpret EF in subtype context instead of as isolated number.', 'Cardiomyopathy - NCLEX', false, 39, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment aligns with Assessment table: heart sounds?', 'Which clinical judgment aligns with Assessment table: heart sounds?', '[{"id": "a", "text": "This pattern is more consistent with Nursing fluid monitoring."}, {"id": "b", "text": "Use auscultation pattern to support subtype differentiation."}, {"id": "c", "text": "No gallop sounds are associated with cardiomyopathy in this note."}, {"id": "d", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}]'::jsonb, '["b"]'::jsonb, 'Correct because Heart sounds: dilated S3, hypertrophic S4, restrictive may have S3 or S4. Use auscultation pattern to support subtype differentiation.', 'Cardiomyopathy - NCLEX', false, 40, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Assessment table: risks in this cardiomyopathy scenario?', 'Which finding best supports Assessment table: risks in this cardiomyopathy scenario?', '[{"id": "a", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "b", "text": "Risk patterns: dilated HF/thromboembolism, hypertrophic sudden death, restrictive HF."}, {"id": "c", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "d", "text": "Hypertrophic type has no sudden death risk in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Risk patterns: dilated HF/thromboembolism, hypertrophic sudden death, restrictive HF. Tailor surveillance to subtype-specific major complications.', 'Cardiomyopathy - NCLEX', false, 41, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for subtype differentiation. Which interpretation matches Medication strategy?', 'The nurse reviews data for subtype differentiation. Which interpretation matches Medication strategy?', '[{"id": "a", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "b", "text": "All cardiomyopathy medications are contraindicated in this note."}, {"id": "c", "text": "Combine workload reduction, decongestion, and rhythm/thromboembolism prevention."}, {"id": "d", "text": "Antiarrhythmics are never used in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Medication classes listed include ACEi/ARB, beta-blockers, diuretics, anticoagulants (especially with A-fib), and antiarrhythmics like amiodarone. Combine workload reduction, decongestion, and rhythm/thromboembolism prevention.', 'Cardiomyopathy - NCLEX', false, 42, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement is most accurate regarding Device and advanced therapy?', 'Which statement is most accurate regarding Device and advanced therapy?', '[{"id": "a", "text": "Interventions include ICD, CRT, LVAD bridge to transplant, and heart transplant for end-stage dilated cardiomyopathy."}, {"id": "b", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "c", "text": "ICD has no role in dangerous rhythms in this note."}, {"id": "d", "text": "This pattern is more consistent with Peripartum alert."}]'::jsonb, '["a"]'::jsonb, 'Correct because Interventions include ICD, CRT, LVAD bridge to transplant, and heart transplant for end-stage dilated cardiomyopathy. Escalate to device/mechanical support when medical therapy is insufficient.', 'Cardiomyopathy - NCLEX', false, 43, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In high-priority cardiology triage, which conclusion fits Lifestyle counseling?', 'In high-priority cardiology triage, which conclusion fits Lifestyle counseling?', '[{"id": "a", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "b", "text": "Reinforce modifiable behaviors that reduce decompensation risk."}, {"id": "c", "text": "Alcohol is therapeutic in cardiomyopathy in this note."}, {"id": "d", "text": "High-sodium diet is encouraged in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Patients are instructed to avoid alcohol, stimulants, and high-sodium diet. Reinforce modifiable behaviors that reduce decompensation risk.', 'Cardiomyopathy - NCLEX', false, 44, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment aligns with Nursing fluid monitoring?', 'Which clinical judgment aligns with Nursing fluid monitoring?', '[{"id": "a", "text": "A 5-lb weekly gain is always normal in this note."}, {"id": "b", "text": "Nursing priority: daily weights, and weight gain >2 lb/day indicates fluid retention requiring provider notification."}, {"id": "c", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "d", "text": "This pattern is more consistent with Dilated cardiomyopathy pattern."}]'::jsonb, '["b"]'::jsonb, 'Correct because Nursing priority: daily weights, and weight gain >2 lb/day indicates fluid retention requiring provider notification. Use rapid weight changes as early warning for worsening HF.', 'Cardiomyopathy - NCLEX', false, 45, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Nursing respiratory/hemodynamic monitoring in this cardiomyopathy scenario?', 'Which finding best supports Nursing respiratory/hemodynamic monitoring in this cardiomyopathy scenario?', '[{"id": "a", "text": "This pattern is more consistent with Dilated causes."}, {"id": "b", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "c", "text": "Positioning and trend monitoring help detect and reduce decompensation."}, {"id": "d", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}]'::jsonb, '["c"]'::jsonb, 'Correct because Nursing monitoring includes I&O, vital signs, SpO2, and HOB elevation 30–45° for dyspnea relief. Positioning and trend monitoring help detect and reduce decompensation.', 'Cardiomyopathy - NCLEX', false, 46, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for subtype differentiation. Which interpretation matches HCM nursing teaching?', 'The nurse reviews data for subtype differentiation. Which interpretation matches HCM nursing teaching?', '[{"id": "a", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "b", "text": "Nitrates are routine HCM therapy in this note."}, {"id": "c", "text": "For HCM, teach no strenuous activity and avoidance of dehydration, Valsalva, and nitrates."}, {"id": "d", "text": "This pattern is more consistent with Dilated signs."}]'::jsonb, '["c"]'::jsonb, 'Correct because For HCM, teach no strenuous activity and avoidance of dehydration, Valsalva, and nitrates. Prevent obstruction-provoked collapse through targeted teaching.', 'Cardiomyopathy - NCLEX', false, 47, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement is most accurate regarding Peripartum alert?', 'Which statement is most accurate regarding Peripartum alert?', '[{"id": "a", "text": "Urgent monitoring is unnecessary because these findings are low-risk."}, {"id": "b", "text": "Screen new mothers promptly for cardiomyopathy warning symptoms."}, {"id": "c", "text": "Postpartum dyspnea is always benign in this note."}, {"id": "d", "text": "This pattern is more consistent with HCM structure."}]'::jsonb, '["b"]'::jsonb, 'Correct because Peripartum cardiomyopathy can occur in the last month of pregnancy or within 5 months postpartum, presenting with unexplained dyspnea/fatigue. Screen new mothers promptly for cardiomyopathy warning symptoms.', 'Cardiomyopathy - NCLEX', false, 48, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In high-priority cardiology triage, which conclusion fits Core definition?', 'In high-priority cardiology triage, which conclusion fits Core definition?', '[{"id": "a", "text": "Cardiomyopathy never affects cardiac output in this note."}, {"id": "b", "text": "Cardiomyopathy is heart muscle disease that can make the heart weak, stretched, or stiff and impair pumping."}, {"id": "c", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "d", "text": "Cardiomyopathy only affects coronary arteries in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Cardiomyopathy is heart muscle disease that can make the heart weak, stretched, or stiff and impair pumping. Monitor for progression to heart failure, dysrhythmias, and sudden cardiac death.', 'Cardiomyopathy - NCLEX', false, 49, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment aligns with Dilated cardiomyopathy pattern?', 'Which clinical judgment aligns with Dilated cardiomyopathy pattern?', '[{"id": "a", "text": "Prioritize systolic failure monitoring and congestion assessment."}, {"id": "b", "text": "Volume-depleting strategies are universally beneficial across all subtypes."}, {"id": "c", "text": "This pattern is more consistent with HCM symptoms."}, {"id": "d", "text": "Dilated type usually has increased EF in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Dilated cardiomyopathy has enlarged chambers, especially LV, with thin weak muscle and reduced ejection fraction. Prioritize systolic failure monitoring and congestion assessment.', 'Cardiomyopathy - NCLEX', false, 50, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Core definition. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Core definition. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "It impairs pumping effectiveness."}, {"id": "b", "text": "Cardiomyopathy only affects coronary arteries in this note."}, {"id": "c", "text": "Cardiomyopathy changes muscle structure/function."}, {"id": "d", "text": "Complications include HF and dysrhythmias."}, {"id": "e", "text": "Cardiomyopathy never affects cardiac output in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Cardiomyopathy is heart muscle disease that can make the heart weak, stretched, or stiff and impair pumping.', 'Cardiomyopathy - NCLEX', true, 51, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For cardiomyopathy management and Dilated cardiomyopathy pattern, which statements are correct? (Select all that apply)', 'For cardiomyopathy management and Dilated cardiomyopathy pattern, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Dilated type has enlarged ventricles in this note."}, {"id": "b", "text": "Dilated type has thick septum with normal chamber size in this note."}, {"id": "c", "text": "Ejection fraction is reduced in dilated type."}, {"id": "d", "text": "Systolic failure is the main issue in dilated type."}, {"id": "e", "text": "Dilated type usually has increased EF in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Dilated cardiomyopathy has enlarged chambers, especially LV, with thin weak muscle and reduced ejection fraction.', 'Cardiomyopathy - NCLEX', true, 52, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Dilated causes. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Dilated causes. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Hypertension is excluded in this note."}, {"id": "b", "text": "Alcohol/drug use is listed cause."}, {"id": "c", "text": "Peripartum cardiomyopathy is included in this note."}, {"id": "d", "text": "Viral myocarditis is listed cause."}, {"id": "e", "text": "Dilated type is only caused by congenital cyanotic defects in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Dilated causes listed include genetics, alcohol/drug use, viral myocarditis, peripartum state, and hypertension.', 'Cardiomyopathy - NCLEX', true, 53, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Dilated signs? (Select all that apply)', 'During reassessment, which observations support Dilated signs? (Select all that apply)', '[{"id": "a", "text": "Edema is absent in dilated type in this note."}, {"id": "b", "text": "SOB/fatigue/edema are listed symptoms."}, {"id": "c", "text": "Displaced PMI is listed finding."}, {"id": "d", "text": "S4 gallop is the defining dilated sound in this note."}, {"id": "e", "text": "S3 gallop is associated with dilated type."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Dilated signs include SOB, fatigue, edema, S3 gallop, and displaced PMI.', 'Cardiomyopathy - NCLEX', true, 54, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which features are consistent with HCM structure in this note? (Select all that apply)', 'Which features are consistent with HCM structure in this note? (Select all that apply)', '[{"id": "a", "text": "Outflow obstruction is central in HCM."}, {"id": "b", "text": "HCM has septal hypertrophy in this note."}, {"id": "c", "text": "HCM always improves outflow in this note."}, {"id": "d", "text": "HCM is primarily chamber dilation in this note."}, {"id": "e", "text": "Cardiac output can decrease in HCM."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Hypertrophic cardiomyopathy features thickened myocardium, especially septum, causing outflow obstruction and decreased cardiac output.', 'Cardiomyopathy - NCLEX', true, 55, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for HCM risk profile. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for HCM risk profile. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "HCM is non-genetic in this note."}, {"id": "b", "text": "Competitive sports restriction is emphasized."}, {"id": "c", "text": "HCM is autosomal dominant in this note."}, {"id": "d", "text": "Young athletes are high risk for sudden death."}, {"id": "e", "text": "Athletic exertion is encouraged in HCM in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: HCM is genetic autosomal dominant and is the most common cause of sudden death in young athletes.', 'Cardiomyopathy - NCLEX', true, 56, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For cardiomyopathy management and HCM symptoms, which statements are correct? (Select all that apply)', 'For cardiomyopathy management and HCM symptoms, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "HCM is always asymptomatic in this note."}, {"id": "b", "text": "Syncope is listed HCM symptom."}, {"id": "c", "text": "S4 gallop is associated with HCM."}, {"id": "d", "text": "Exertional dyspnea is listed symptom."}, {"id": "e", "text": "S3 is the hallmark HCM sound in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: HCM signs include exertional SOB, syncope, chest pain, and S4 gallop.', 'Cardiomyopathy - NCLEX', true, 57, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around HCM exacerbators. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around HCM exacerbators. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Dehydration improves HCM symptoms in this note."}, {"id": "b", "text": "Nitrates are avoided in HCM in this note."}, {"id": "c", "text": "Nitrates are first-line for HCM obstruction in this note."}, {"id": "d", "text": "Dehydration worsens HCM in this note."}, {"id": "e", "text": "Valsalva worsens HCM in this note."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: HCM symptoms worsen with dehydration and Valsalva; nitrates should be avoided.', 'Cardiomyopathy - NCLEX', true, 58, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Restrictive pattern? (Select all that apply)', 'During reassessment, which observations support Restrictive pattern? (Select all that apply)', '[{"id": "a", "text": "Restrictive type has stiffness and poor filling."}, {"id": "b", "text": "Restrictive type has no congestion risk in this note."}, {"id": "c", "text": "Restrictive type is primarily hypercontractile with easy filling in this note."}, {"id": "d", "text": "Blood can back up into lungs/body in restrictive type."}, {"id": "e", "text": "Diastolic failure is the main restrictive issue."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Restrictive cardiomyopathy has stiff myocardium with impaired filling and backup into lungs/body.', 'Cardiomyopathy - NCLEX', true, 59, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which features are consistent with Restrictive causes in this note? (Select all that apply)', 'Which features are consistent with Restrictive causes in this note? (Select all that apply)', '[{"id": "a", "text": "Amyloidosis is listed restrictive cause."}, {"id": "b", "text": "Sarcoidosis is listed restrictive cause."}, {"id": "c", "text": "Alcohol alone is the only restrictive cause in this note."}, {"id": "d", "text": "Radiation therapy is listed restrictive cause."}, {"id": "e", "text": "Radiation is unrelated to restrictive disease in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Restrictive causes listed are amyloidosis, sarcoidosis, and radiation therapy.', 'Cardiomyopathy - NCLEX', true, 60, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for ARVC pathology. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for ARVC pathology. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "ARVC carries sudden cardiac death risk."}, {"id": "b", "text": "ARVC primarily causes left ventricular dilation only in this note."}, {"id": "c", "text": "ARVC raises V-tach/V-fib risk."}, {"id": "d", "text": "RV fat/scar replacement is core ARVC pathology."}, {"id": "e", "text": "ARVC has no arrhythmia risk in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: ARVC replaces right ventricular muscle with fat/scar tissue, creating dangerous arrhythmias and sudden death risk.', 'Cardiomyopathy - NCLEX', true, 61, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For cardiomyopathy management and ARVC epidemiology, which statements are correct? (Select all that apply)', 'For cardiomyopathy management and ARVC epidemiology, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "ARVC is autosomal dominant in this note."}, {"id": "b", "text": "Young males/athletes are highlighted risk groups."}, {"id": "c", "text": "ARVC is exclusively acquired after age 80 in this note."}, {"id": "d", "text": "Family-risk context matters in ARVC."}, {"id": "e", "text": "Athletes are protected from ARVC in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: ARVC is genetic autosomal dominant and often seen in young males and athletes.', 'Cardiomyopathy - NCLEX', true, 62, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around ARVC diagnosis treatment. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around ARVC diagnosis treatment. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Echocardiogram alone is gold standard for ARVC in this note."}, {"id": "b", "text": "MRI is gold-standard in ARVC note."}, {"id": "c", "text": "Competitive sports avoidance is listed ARVC management."}, {"id": "d", "text": "ICD is listed ARVC intervention."}, {"id": "e", "text": "ARVC treatment encourages strenuous sports in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: MRI is gold standard for ARVC; treatment includes ICD, amiodarone, activity restriction, and avoiding competitive sports.', 'Cardiomyopathy - NCLEX', true, 63, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Common pathophysiology? (Select all that apply)', 'During reassessment, which observations support Common pathophysiology? (Select all that apply)', '[{"id": "a", "text": "Lower CO is a shared pathway in this note."}, {"id": "b", "text": "Fluid buildup can occur across types."}, {"id": "c", "text": "Fatigue and dyspnea arise from low output/congestion."}, {"id": "d", "text": "Cardiomyopathy never leads to fluid overload in this note."}, {"id": "e", "text": "All types increase cardiac output in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Across cardiomyopathies, reduced pumping lowers cardiac output and causes fatigue, dyspnea, and fluid buildup.', 'Cardiomyopathy - NCLEX', true, 64, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which features are consistent with Assessment table: EF in this note? (Select all that apply)', 'Which features are consistent with Assessment table: EF in this note? (Select all that apply)', '[{"id": "a", "text": "HCM EF can be normal or increased."}, {"id": "b", "text": "Dilated EF is normal in this note."}, {"id": "c", "text": "HCM always has reduced EF in this note."}, {"id": "d", "text": "Restrictive EF can be normal or reduced."}, {"id": "e", "text": "Dilated EF is reduced in this note."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: EF trends: dilated decreased, hypertrophic normal/increased, restrictive normal or decreased.', 'Cardiomyopathy - NCLEX', true, 65, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Assessment table: heart sounds. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Assessment table: heart sounds. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "S4 is unique to dilated type in this note."}, {"id": "b", "text": "S4 is linked to hypertrophic type."}, {"id": "c", "text": "No gallop sounds are associated with cardiomyopathy in this note."}, {"id": "d", "text": "S3 is linked to dilated type."}, {"id": "e", "text": "Restrictive may present S3 or S4."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Heart sounds: dilated S3, hypertrophic S4, restrictive may have S3 or S4.', 'Cardiomyopathy - NCLEX', true, 66, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For cardiomyopathy management and Assessment table: risks, which statements are correct? (Select all that apply)', 'For cardiomyopathy management and Assessment table: risks, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Dilated type has thromboembolism risk in this note."}, {"id": "b", "text": "Hypertrophic type has no sudden death risk in this note."}, {"id": "c", "text": "Restrictive type risk is only stroke in this note."}, {"id": "d", "text": "Restrictive type is linked with HF risk."}, {"id": "e", "text": "Hypertrophic type has sudden death risk."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Risk patterns: dilated HF/thromboembolism, hypertrophic sudden death, restrictive HF.', 'Cardiomyopathy - NCLEX', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Medication strategy. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Medication strategy. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Diuretics are listed for fluid overload."}, {"id": "b", "text": "Antiarrhythmics are never used in this note."}, {"id": "c", "text": "All cardiomyopathy medications are contraindicated in this note."}, {"id": "d", "text": "Anticoagulants are noted especially with A-fib."}, {"id": "e", "text": "ACEi/ARB and beta-blockers are listed therapies."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Medication classes listed include ACEi/ARB, beta-blockers, diuretics, anticoagulants (especially with A-fib), and antiarrhythmics like amiodarone.', 'Cardiomyopathy - NCLEX', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Device and advanced therapy? (Select all that apply)', 'During reassessment, which observations support Device and advanced therapy? (Select all that apply)', '[{"id": "a", "text": "ICD is listed for life-threatening arrhythmias."}, {"id": "b", "text": "LVAD is used only for temporary arrhythmia suppression in this note."}, {"id": "c", "text": "ICD has no role in dangerous rhythms in this note."}, {"id": "d", "text": "LVAD is a bridge strategy in failing LV."}, {"id": "e", "text": "Transplant is listed for end-stage dilated disease."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Interventions include ICD, CRT, LVAD bridge to transplant, and heart transplant for end-stage dilated cardiomyopathy.', 'Cardiomyopathy - NCLEX', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which features are consistent with Lifestyle counseling in this note? (Select all that apply)', 'Which features are consistent with Lifestyle counseling in this note? (Select all that apply)', '[{"id": "a", "text": "High-sodium diet is encouraged in this note."}, {"id": "b", "text": "Alcohol avoidance is recommended."}, {"id": "c", "text": "High sodium intake should be avoided."}, {"id": "d", "text": "Stimulant avoidance is recommended."}, {"id": "e", "text": "Alcohol is therapeutic in cardiomyopathy in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Patients are instructed to avoid alcohol, stimulants, and high-sodium diet.', 'Cardiomyopathy - NCLEX', true, 70, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Nursing fluid monitoring. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Nursing fluid monitoring. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Daily weights are unnecessary in this note."}, {"id": "b", "text": "Daily weight is emphasized in nursing care."}, {"id": "c", "text": "Provider should be notified for rapid gain."}, {"id": "d", "text": "A 5-lb weekly gain is always normal in this note."}, {"id": "e", "text": ">2 lb/day gain is concerning in this note."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Nursing priority: daily weights, and weight gain >2 lb/day indicates fluid retention requiring provider notification.', 'Cardiomyopathy - NCLEX', true, 71, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For cardiomyopathy management and Nursing respiratory/hemodynamic monitoring, which statements are correct? (Select all that apply)', 'For cardiomyopathy management and Nursing respiratory/hemodynamic monitoring, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "SpO2 and vitals are ongoing priorities."}, {"id": "b", "text": "HOB 30–45° helps dyspnea in this note."}, {"id": "c", "text": "I&O monitoring is listed."}, {"id": "d", "text": "SpO2 monitoring is not needed in this note."}, {"id": "e", "text": "Flat supine positioning is preferred for dyspnea in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Nursing monitoring includes I&O, vital signs, SpO2, and HOB elevation 30–45° for dyspnea relief.', 'Cardiomyopathy - NCLEX', true, 72, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around HCM nursing teaching. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around HCM nursing teaching. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Nitrates are routine HCM therapy in this note."}, {"id": "b", "text": "Valsalva is encouraged for HCM symptom control in this note."}, {"id": "c", "text": "Avoid nitrates in HCM in this note."}, {"id": "d", "text": "No strenuous activity is taught for HCM."}, {"id": "e", "text": "Avoid dehydration/Valsalva in HCM."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: For HCM, teach no strenuous activity and avoidance of dehydration, Valsalva, and nitrates.', 'Cardiomyopathy - NCLEX', true, 73, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Peripartum alert? (Select all that apply)', 'During reassessment, which observations support Peripartum alert? (Select all that apply)', '[{"id": "a", "text": "Postpartum risk window extends 5 months."}, {"id": "b", "text": "Unexplained dyspnea/fatigue in new moms is concerning."}, {"id": "c", "text": "Peripartum window includes last pregnancy month in this note."}, {"id": "d", "text": "Postpartum dyspnea is always benign in this note."}, {"id": "e", "text": "Peripartum cardiomyopathy only occurs years after delivery in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Peripartum cardiomyopathy can occur in the last month of pregnancy or within 5 months postpartum, presenting with unexplained dyspnea/fatigue.', 'Cardiomyopathy - NCLEX', true, 74, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which features are consistent with Core definition in this note? (Select all that apply)', 'Which features are consistent with Core definition in this note? (Select all that apply)', '[{"id": "a", "text": "It impairs pumping effectiveness."}, {"id": "b", "text": "Cardiomyopathy never affects cardiac output in this note."}, {"id": "c", "text": "Cardiomyopathy changes muscle structure/function."}, {"id": "d", "text": "Complications include HF and dysrhythmias."}, {"id": "e", "text": "Cardiomyopathy only affects coronary arteries in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Cardiomyopathy is heart muscle disease that can make the heart weak, stretched, or stiff and impair pumping.', 'Cardiomyopathy - NCLEX', true, 75, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Dilated cardiomyopathy pattern. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Dilated cardiomyopathy pattern. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Dilated type has thick septum with normal chamber size in this note."}, {"id": "b", "text": "Ejection fraction is reduced in dilated type."}, {"id": "c", "text": "Systolic failure is the main issue in dilated type."}, {"id": "d", "text": "Dilated type usually has increased EF in this note."}, {"id": "e", "text": "Dilated type has enlarged ventricles in this note."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Dilated cardiomyopathy has enlarged chambers, especially LV, with thin weak muscle and reduced ejection fraction.', 'Cardiomyopathy - NCLEX', true, 76, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For cardiomyopathy management and Dilated causes, which statements are correct? (Select all that apply)', 'For cardiomyopathy management and Dilated causes, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Alcohol/drug use is listed cause."}, {"id": "b", "text": "Viral myocarditis is listed cause."}, {"id": "c", "text": "Peripartum cardiomyopathy is included in this note."}, {"id": "d", "text": "Hypertension is excluded in this note."}, {"id": "e", "text": "Dilated type is only caused by congenital cyanotic defects in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Dilated causes listed include genetics, alcohol/drug use, viral myocarditis, peripartum state, and hypertension.', 'Cardiomyopathy - NCLEX', true, 77, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Dilated signs. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Dilated signs. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "SOB/fatigue/edema are listed symptoms."}, {"id": "b", "text": "Displaced PMI is listed finding."}, {"id": "c", "text": "S3 gallop is associated with dilated type."}, {"id": "d", "text": "Edema is absent in dilated type in this note."}, {"id": "e", "text": "S4 gallop is the defining dilated sound in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Dilated signs include SOB, fatigue, edema, S3 gallop, and displaced PMI.', 'Cardiomyopathy - NCLEX', true, 78, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support HCM structure? (Select all that apply)', 'During reassessment, which observations support HCM structure? (Select all that apply)', '[{"id": "a", "text": "HCM has septal hypertrophy in this note."}, {"id": "b", "text": "HCM always improves outflow in this note."}, {"id": "c", "text": "HCM is primarily chamber dilation in this note."}, {"id": "d", "text": "Cardiac output can decrease in HCM."}, {"id": "e", "text": "Outflow obstruction is central in HCM."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Hypertrophic cardiomyopathy features thickened myocardium, especially septum, causing outflow obstruction and decreased cardiac output.', 'Cardiomyopathy - NCLEX', true, 79, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which features are consistent with HCM risk profile in this note? (Select all that apply)', 'Which features are consistent with HCM risk profile in this note? (Select all that apply)', '[{"id": "a", "text": "Competitive sports restriction is emphasized."}, {"id": "b", "text": "Athletic exertion is encouraged in HCM in this note."}, {"id": "c", "text": "Young athletes are high risk for sudden death."}, {"id": "d", "text": "HCM is non-genetic in this note."}, {"id": "e", "text": "HCM is autosomal dominant in this note."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: HCM is genetic autosomal dominant and is the most common cause of sudden death in young athletes.', 'Cardiomyopathy - NCLEX', true, 80, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for HCM symptoms. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for HCM symptoms. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Syncope is listed HCM symptom."}, {"id": "b", "text": "Exertional dyspnea is listed symptom."}, {"id": "c", "text": "S3 is the hallmark HCM sound in this note."}, {"id": "d", "text": "S4 gallop is associated with HCM."}, {"id": "e", "text": "HCM is always asymptomatic in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: HCM signs include exertional SOB, syncope, chest pain, and S4 gallop.', 'Cardiomyopathy - NCLEX', true, 81, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For cardiomyopathy management and HCM exacerbators, which statements are correct? (Select all that apply)', 'For cardiomyopathy management and HCM exacerbators, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Dehydration improves HCM symptoms in this note."}, {"id": "b", "text": "Valsalva worsens HCM in this note."}, {"id": "c", "text": "Nitrates are first-line for HCM obstruction in this note."}, {"id": "d", "text": "Nitrates are avoided in HCM in this note."}, {"id": "e", "text": "Dehydration worsens HCM in this note."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: HCM symptoms worsen with dehydration and Valsalva; nitrates should be avoided.', 'Cardiomyopathy - NCLEX', true, 82, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Restrictive pattern. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Restrictive pattern. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Restrictive type has no congestion risk in this note."}, {"id": "b", "text": "Restrictive type is primarily hypercontractile with easy filling in this note."}, {"id": "c", "text": "Blood can back up into lungs/body in restrictive type."}, {"id": "d", "text": "Diastolic failure is the main restrictive issue."}, {"id": "e", "text": "Restrictive type has stiffness and poor filling."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Restrictive cardiomyopathy has stiff myocardium with impaired filling and backup into lungs/body.', 'Cardiomyopathy - NCLEX', true, 83, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Restrictive causes? (Select all that apply)', 'During reassessment, which observations support Restrictive causes? (Select all that apply)', '[{"id": "a", "text": "Alcohol alone is the only restrictive cause in this note."}, {"id": "b", "text": "Radiation is unrelated to restrictive disease in this note."}, {"id": "c", "text": "Sarcoidosis is listed restrictive cause."}, {"id": "d", "text": "Amyloidosis is listed restrictive cause."}, {"id": "e", "text": "Radiation therapy is listed restrictive cause."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Restrictive causes listed are amyloidosis, sarcoidosis, and radiation therapy.', 'Cardiomyopathy - NCLEX', true, 84, 1, true);
