  VALUES (v_test_id, v_topic_id, 'Which features are consistent with ARVC pathology in this note? (Select all that apply)', 'Which features are consistent with ARVC pathology in this note? (Select all that apply)', '[{"id": "a", "text": "RV fat/scar replacement is core ARVC pathology."}, {"id": "b", "text": "ARVC primarily causes left ventricular dilation only in this note."}, {"id": "c", "text": "ARVC carries sudden cardiac death risk."}, {"id": "d", "text": "ARVC has no arrhythmia risk in this note."}, {"id": "e", "text": "ARVC raises V-tach/V-fib risk."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: ARVC replaces right ventricular muscle with fat/scar tissue, creating dangerous arrhythmias and sudden death risk.', 'Cardiomyopathy - NCLEX', true, 85, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for ARVC epidemiology. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for ARVC epidemiology. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Family-risk context matters in ARVC."}, {"id": "b", "text": "ARVC is exclusively acquired after age 80 in this note."}, {"id": "c", "text": "Young males/athletes are highlighted risk groups."}, {"id": "d", "text": "ARVC is autosomal dominant in this note."}, {"id": "e", "text": "Athletes are protected from ARVC in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: ARVC is genetic autosomal dominant and often seen in young males and athletes.', 'Cardiomyopathy - NCLEX', true, 86, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For cardiomyopathy management and ARVC diagnosis treatment, which statements are correct? (Select all that apply)', 'For cardiomyopathy management and ARVC diagnosis treatment, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Echocardiogram alone is gold standard for ARVC in this note."}, {"id": "b", "text": "MRI is gold-standard in ARVC note."}, {"id": "c", "text": "Competitive sports avoidance is listed ARVC management."}, {"id": "d", "text": "ARVC treatment encourages strenuous sports in this note."}, {"id": "e", "text": "ICD is listed ARVC intervention."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: MRI is gold standard for ARVC; treatment includes ICD, amiodarone, activity restriction, and avoiding competitive sports.', 'Cardiomyopathy - NCLEX', true, 87, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Common pathophysiology. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Common pathophysiology. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Cardiomyopathy never leads to fluid overload in this note."}, {"id": "b", "text": "Fatigue and dyspnea arise from low output/congestion."}, {"id": "c", "text": "All types increase cardiac output in this note."}, {"id": "d", "text": "Fluid buildup can occur across types."}, {"id": "e", "text": "Lower CO is a shared pathway in this note."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Across cardiomyopathies, reduced pumping lowers cardiac output and causes fatigue, dyspnea, and fluid buildup.', 'Cardiomyopathy - NCLEX', true, 88, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Assessment table: EF? (Select all that apply)', 'During reassessment, which observations support Assessment table: EF? (Select all that apply)', '[{"id": "a", "text": "Restrictive EF can be normal or reduced."}, {"id": "b", "text": "Dilated EF is reduced in this note."}, {"id": "c", "text": "HCM always has reduced EF in this note."}, {"id": "d", "text": "HCM EF can be normal or increased."}, {"id": "e", "text": "Dilated EF is normal in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: EF trends: dilated decreased, hypertrophic normal/increased, restrictive normal or decreased.', 'Cardiomyopathy - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which features are consistent with Assessment table: heart sounds in this note? (Select all that apply)', 'Which features are consistent with Assessment table: heart sounds in this note? (Select all that apply)', '[{"id": "a", "text": "S3 is linked to dilated type."}, {"id": "b", "text": "S4 is linked to hypertrophic type."}, {"id": "c", "text": "Restrictive may present S3 or S4."}, {"id": "d", "text": "No gallop sounds are associated with cardiomyopathy in this note."}, {"id": "e", "text": "S4 is unique to dilated type in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Heart sounds: dilated S3, hypertrophic S4, restrictive may have S3 or S4.', 'Cardiomyopathy - NCLEX', true, 90, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Assessment table: risks. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Assessment table: risks. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Hypertrophic type has sudden death risk."}, {"id": "b", "text": "Hypertrophic type has no sudden death risk in this note."}, {"id": "c", "text": "Restrictive type is linked with HF risk."}, {"id": "d", "text": "Dilated type has thromboembolism risk in this note."}, {"id": "e", "text": "Restrictive type risk is only stroke in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Risk patterns: dilated HF/thromboembolism, hypertrophic sudden death, restrictive HF.', 'Cardiomyopathy - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For cardiomyopathy management and Medication strategy, which statements are correct? (Select all that apply)', 'For cardiomyopathy management and Medication strategy, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "ACEi/ARB and beta-blockers are listed therapies."}, {"id": "b", "text": "All cardiomyopathy medications are contraindicated in this note."}, {"id": "c", "text": "Anticoagulants are noted especially with A-fib."}, {"id": "d", "text": "Antiarrhythmics are never used in this note."}, {"id": "e", "text": "Diuretics are listed for fluid overload."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Medication classes listed include ACEi/ARB, beta-blockers, diuretics, anticoagulants (especially with A-fib), and antiarrhythmics like amiodarone.', 'Cardiomyopathy - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Device and advanced therapy. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Device and advanced therapy. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "LVAD is used only for temporary arrhythmia suppression in this note."}, {"id": "b", "text": "ICD has no role in dangerous rhythms in this note."}, {"id": "c", "text": "ICD is listed for life-threatening arrhythmias."}, {"id": "d", "text": "LVAD is a bridge strategy in failing LV."}, {"id": "e", "text": "Transplant is listed for end-stage dilated disease."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Interventions include ICD, CRT, LVAD bridge to transplant, and heart transplant for end-stage dilated cardiomyopathy.', 'Cardiomyopathy - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Lifestyle counseling? (Select all that apply)', 'During reassessment, which observations support Lifestyle counseling? (Select all that apply)', '[{"id": "a", "text": "Alcohol avoidance is recommended."}, {"id": "b", "text": "High sodium intake should be avoided."}, {"id": "c", "text": "High-sodium diet is encouraged in this note."}, {"id": "d", "text": "Stimulant avoidance is recommended."}, {"id": "e", "text": "Alcohol is therapeutic in cardiomyopathy in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Patients are instructed to avoid alcohol, stimulants, and high-sodium diet.', 'Cardiomyopathy - NCLEX', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which features are consistent with Nursing fluid monitoring in this note? (Select all that apply)', 'Which features are consistent with Nursing fluid monitoring in this note? (Select all that apply)', '[{"id": "a", "text": ">2 lb/day gain is concerning in this note."}, {"id": "b", "text": "Daily weights are unnecessary in this note."}, {"id": "c", "text": "Provider should be notified for rapid gain."}, {"id": "d", "text": "A 5-lb weekly gain is always normal in this note."}, {"id": "e", "text": "Daily weight is emphasized in nursing care."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Nursing priority: daily weights, and weight gain >2 lb/day indicates fluid retention requiring provider notification.', 'Cardiomyopathy - NCLEX', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Nursing respiratory/hemodynamic monitoring. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Nursing respiratory/hemodynamic monitoring. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "SpO2 monitoring is not needed in this note."}, {"id": "b", "text": "SpO2 and vitals are ongoing priorities."}, {"id": "c", "text": "I&O monitoring is listed."}, {"id": "d", "text": "HOB 30–45° helps dyspnea in this note."}, {"id": "e", "text": "Flat supine positioning is preferred for dyspnea in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Nursing monitoring includes I&O, vital signs, SpO2, and HOB elevation 30–45° for dyspnea relief.', 'Cardiomyopathy - NCLEX', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For cardiomyopathy management and HCM nursing teaching, which statements are correct? (Select all that apply)', 'For cardiomyopathy management and HCM nursing teaching, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Nitrates are routine HCM therapy in this note."}, {"id": "b", "text": "Avoid dehydration/Valsalva in HCM."}, {"id": "c", "text": "Avoid nitrates in HCM in this note."}, {"id": "d", "text": "No strenuous activity is taught for HCM."}, {"id": "e", "text": "Valsalva is encouraged for HCM symptom control in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: For HCM, teach no strenuous activity and avoidance of dehydration, Valsalva, and nitrates.', 'Cardiomyopathy - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Peripartum alert. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Peripartum alert. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Peripartum window includes last pregnancy month in this note."}, {"id": "b", "text": "Peripartum cardiomyopathy only occurs years after delivery in this note."}, {"id": "c", "text": "Unexplained dyspnea/fatigue in new moms is concerning."}, {"id": "d", "text": "Postpartum risk window extends 5 months."}, {"id": "e", "text": "Postpartum dyspnea is always benign in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Peripartum cardiomyopathy can occur in the last month of pregnancy or within 5 months postpartum, presenting with unexplained dyspnea/fatigue.', 'Cardiomyopathy - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Core definition? (Select all that apply)', 'During reassessment, which observations support Core definition? (Select all that apply)', '[{"id": "a", "text": "Cardiomyopathy changes muscle structure/function."}, {"id": "b", "text": "It impairs pumping effectiveness."}, {"id": "c", "text": "Cardiomyopathy never affects cardiac output in this note."}, {"id": "d", "text": "Complications include HF and dysrhythmias."}, {"id": "e", "text": "Cardiomyopathy only affects coronary arteries in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Cardiomyopathy is heart muscle disease that can make the heart weak, stretched, or stiff and impair pumping.', 'Cardiomyopathy - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which features are consistent with Dilated cardiomyopathy pattern in this note? (Select all that apply)', 'Which features are consistent with Dilated cardiomyopathy pattern in this note? (Select all that apply)', '[{"id": "a", "text": "Ejection fraction is reduced in dilated type."}, {"id": "b", "text": "Systolic failure is the main issue in dilated type."}, {"id": "c", "text": "Dilated type has enlarged ventricles in this note."}, {"id": "d", "text": "Dilated type usually has increased EF in this note."}, {"id": "e", "text": "Dilated type has thick septum with normal chamber size in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Dilated cardiomyopathy has enlarged chambers, especially LV, with thin weak muscle and reduced ejection fraction.', 'Cardiomyopathy - NCLEX', true, 100, 1, true);
